1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const quotePremium = (items: Item[]): number => {
15	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
16	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
17	  return policyBase + firstInsuranceSurcharge + PROCESSING_FEE;
18	};
19	
20	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
21	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
22	  return { results };
23	};
